// Flatten each venue's events_sources array into individual items.
// Each item = one venue × one source to process.
const results = [];
for (const item of $input.all()) {
  const venue = item.json;
  let sources = venue.events_sources;
  if (typeof sources === 'string') {
    try { sources = JSON.parse(sources); } catch { sources = []; }
  }
  if (!Array.isArray(sources) || sources.length === 0) continue;
  for (const source of sources) {
    results.push({
      json: {
        slug:             venue.slug,
        name:             venue.name,
        facebookPageId:   venue.facebook_page_id  ?? null,
        instagramPageId:  venue.instagram_page_id ?? null,
        googleCalendarId: venue.google_calendar_id ?? null,
        sourceType:       source.type,
        sourceUrl:        source.url,
      },
    });
  }
}
return results;

// Phase 2 placeholder — Instagram scraping requires Graph API access from the venue
// or Claude AI-assisted caption parsing. Skipped for now.
const slug = $json.slug ?? 'unknown';
console.log(`[venue-events-sync] SKIP ${slug} instagram source — Phase 2 not yet implemented`);
return [];

// Website scraping not yet wired — add HTTP Request + HTML Extract nodes here
// when venue website URLs are confirmed (Ruby's Elixir, Blueberry Patch).
const slug = $json.slug ?? 'unknown';
console.log(`[venue-events-sync] SKIP ${slug} website source — scraper not yet wired`);
return [];

// ── Attempt 1: Facebook Graph API with App Access Token ──────────────────────
// App access tokens are formed as {app_id}|{app_secret} — no user login needed.
// Works for public pages if the app has pages_read_engagement permission.
// Returns null on failure so the next node can fall back to mbasic.
const item = $input.first().json;
const pageId    = item.facebookPageId;
const appId     = $env.FB_APP_ID;
const appSecret = $env.FB_APP_SECRET;

if (!pageId) {
  console.log(`[venue-events-sync] ${item.slug}: no facebook_page_id set — skipping Graph API attempt`);
  return [{ json: { ...item, graphApiEvents: null, graphApiSkipped: true } }];
}
if (!appId || !appSecret) {
  console.log(`[venue-events-sync] ${item.slug}: FB_APP_ID or FB_APP_SECRET not set — skipping Graph API attempt`);
  return [{ json: { ...item, graphApiEvents: null, graphApiSkipped: true } }];
}

const nowUnix = Math.floor(Date.now() / 1000);
const maxUnix = nowUnix + 60 * 24 * 60 * 60; // 60 days out
const token   = `${appId}|${appSecret}`;
const fields  = 'id,name,description,start_time,end_time,cover,ticket_uri,place';
const url = `https://graph.facebook.com/v21.0/${pageId}/events` +
  `?access_token=${encodeURIComponent(token)}` +
  `&fields=${fields}` +
  `&since=${nowUnix}` +
  `&until=${maxUnix}` +
  `&limit=50`;

try {
  const resp = await fetch(url);
  const body = await resp.json();
  if (body.error) {
    console.log(`[venue-events-sync] ${item.slug}: Graph API error — ${body.error.message}`);
    return [{ json: { ...item, graphApiEvents: null, graphApiError: body.error.message } }];
  }
  const events = body.data ?? [];
  console.log(`[venue-events-sync] ${item.slug}: Graph API returned ${events.length} events`);
  return [{ json: { ...item, graphApiEvents: events } }];
} catch (err) {
  console.log(`[venue-events-sync] ${item.slug}: Graph API fetch threw — ${err.message}`);
  return [{ json: { ...item, graphApiEvents: null, graphApiFetchError: err.message } }];
}

// ── Attempt 2: mbasic.facebook.com HTML scraping ─────────────────────────────
// Only runs if Graph API returned 0 events or failed.
// mbasic is Facebook's server-rendered site (no JS needed).
// Uses a realistic mobile User-Agent; runs once/week — low detection risk.
const item = $input.first().json;

// If Graph API already returned events, pass them through and skip mbasic.
if (Array.isArray(item.graphApiEvents) && item.graphApiEvents.length > 0) {
  return [{ json: { ...item, usedSource: 'graph_api' } }];
}

const slug = item.slug;
const mbasicUrl = `https://mbasic.facebook.com/${slug}/events`;
console.log(`[venue-events-sync] ${slug}: Graph API empty/failed — trying mbasic: ${mbasicUrl}`);

try {
  const resp = await fetch(mbasicUrl, {
    headers: {
      'User-Agent': 'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.0 Mobile/15E148 Safari/604.1',
      'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
      'Accept-Language': 'en-US,en;q=0.9',
    },
  });

  if (!resp.ok) {
    console.log(`[venue-events-sync] ${slug}: mbasic returned HTTP ${resp.status}`);
    return [{ json: { ...item, mbasicHtml: null, usedSource: 'none', mbasicStatus: resp.status } }];
  }

  const html = await resp.text();
  if (html.includes('You must log in') || html.includes('login_form')) {
    console.log(`[venue-events-sync] ${slug}: mbasic redirected to login — blocked this run`);
    return [{ json: { ...item, mbasicHtml: null, usedSource: 'none', mbasicBlocked: true } }];
  }

  return [{ json: { ...item, mbasicHtml: html, usedSource: 'mbasic' } }];
} catch (err) {
  console.log(`[venue-events-sync] ${slug}: mbasic fetch threw — ${err.message}`);
  return [{ json: { ...item, mbasicHtml: null, usedSource: 'none', mbasicFetchError: err.message } }];
}

// ── Normalize + Filter events from whichever source succeeded ────────────────
// Handles both Graph API JSON format and mbasic HTML (parsed with cheerio).
// Filters to events starting within the next 60 days.
// Generates a stable dedup_id: "fb_{fbEventId}" for GCal + DB upsert.

const item = $input.first().json;
const slug  = item.slug;
const now   = Date.now();
const max   = now + 60 * 24 * 60 * 60 * 1000;

function parseDateToMs(str) {
  if (!str) return null;
  return new Date(str).getTime();
}

function extractFbEventId(url) {
  if (!url) return null;
  const m = String(url).match(/\/events\/(\d+)/);
  return m ? m[1] : null;
}

let normalised = [];

// ── Source A: Graph API JSON ──────────────────────────────────────────────────
if (Array.isArray(item.graphApiEvents) && item.graphApiEvents.length > 0) {
  for (const ev of item.graphApiEvents) {
    try {
      const startMs = parseDateToMs(ev.start_time);
      if (!startMs || startMs < now || startMs > max) continue;
      const fbEventId = String(ev.id);
      if (!fbEventId) continue;
      normalised.push({
        fbEventId,
        dedup_id:    `fb_${fbEventId}`,
        title:       ev.name ?? '',
        description: ev.description ?? null,
        startTime:   ev.start_time,
        endTime:     ev.end_time ?? null,
        imageUrl:    ev.cover?.source ?? null,
        ticketUrl:   ev.ticket_uri ?? null,
        eventBy:     ev.place?.name ?? null,
        fbEventUrl:  `https://www.facebook.com/events/${fbEventId}`,
        source:      'graph_api',
      });
    } catch (e) {
      console.log(`[venue-events-sync] ${slug}: error normalising graph_api event — ${e.message}`);
    }
  }
  console.log(`[venue-events-sync] ${slug}: normalised ${normalised.length} events from graph_api`);
}

// ── Source B: mbasic HTML ─────────────────────────────────────────────────────
if (normalised.length === 0 && item.mbasicHtml) {
  try {
    const cheerio = require('cheerio');
    const $ = cheerio.load(item.mbasicHtml);

    $('a[href*="/events/"]').each((_, el) => {
      try {
        const href = $(el).attr('href') ?? '';
        const fbEventId = extractFbEventId(href);
        if (!fbEventId) return;

        const title = $(el).find('h3,h4,strong,b').first().text().trim()
          || $(el).text().trim();
        if (!title || title.length < 3) return;

        const parentText = $(el).parent().text();
        const dateMatch = parentText.match(
          /([A-Z][a-z]+,?\s+[A-Z][a-z]+\s+\d{1,2}(?:,?\s+\d{4})?(?:\s+at\s+\d{1,2}:\d{2}\s*[AP]M)?)/i
        );
        const dateStr = dateMatch ? dateMatch[1] : null;
        const startMs = dateStr ? parseDateToMs(dateStr) : null;
        if (startMs && (startMs < now || startMs > max)) return;

        if (normalised.some(e => e.fbEventId === fbEventId)) return;

        const absUrl = href.startsWith('http')
          ? href
          : `https://www.facebook.com${href.split('?')[0]}`;

        normalised.push({
          fbEventId,
          dedup_id:    `fb_${fbEventId}`,
          title,
          description: null,
          startTime:   dateStr ? new Date(dateStr).toISOString() : null,
          endTime:     null,
          imageUrl:    null,
          ticketUrl:   null,
          eventBy:     null,
          fbEventUrl:  absUrl,
          source:      'mbasic',
        });
      } catch (innerErr) {
        // skip this element silently
      }
    });
    console.log(`[venue-events-sync] ${slug}: normalised ${normalised.length} events from mbasic`);
  } catch (e) {
    console.log(`[venue-events-sync] ${slug}: mbasic parse error — ${e.message}`);
  }
}

if (normalised.length === 0) {
  console.log(`[venue-events-sync] ${slug}: 0 events found this run (source: ${item.usedSource ?? 'none'})`);
  return [];
}

return normalised.map(ev => ({
  json: {
    _slug:           item.slug,
    _calendarId:     item.googleCalendarId,
    ...ev,
  },
}));

// Check if the event already exists in GCal by matching dedup_id in description
// or by close title + date match.
const eventItem = $('Loop Over Events').first().json;
const gcalResults = $input.all();

const dedupId    = eventItem.dedup_id ?? '';
const eventTitle = (eventItem.title ?? '').toLowerCase().trim();
const eventStart = eventItem.startTime ? new Date(eventItem.startTime).getTime() : null;

let found = null;
for (const r of gcalResults) {
  const desc  = (r.json.description ?? '').toLowerCase();
  const title = (r.json.summary    ?? '').toLowerCase().trim();
  const start = r.json.start?.dateTime ? new Date(r.json.start.dateTime).getTime() : null;

  if (dedupId && desc.includes(`[dedup_id: ${dedupId}]`)) { found = r.json; break; }
  if (eventTitle && title === eventTitle && eventStart && start) {
    if (Math.abs(eventStart - start) / (1000 * 60 * 60) <= 12) { found = r.json; break; }
  }
}

return [{
  json: {
    ...eventItem,
    _gcalExists:  !!found,
    _gcalEventId: found?.id ?? null,
  },
}];

// Build the GCal event description with structured metadata.
// The [dedup_id: fb_XXX] anchor is used by the duplicate-check node on future runs.
const ev = $input.first().json;

const parts = [];
if (ev.eventBy)   parts.push(`Presented by: ${ev.eventBy}`);
if (ev.ticketUrl) parts.push(`Tickets: ${ev.ticketUrl}`);
if (ev.description) { parts.push('---'); parts.push(ev.description); }
parts.push('');
if (ev.fbEventUrl) parts.push(`Source: ${ev.fbEventUrl}`);
parts.push(`[dedup_id: ${ev.dedup_id}]`);

const description = parts.join('\n').trim();

function toRFC3339(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d.toISOString();
}

return [{ json: {
  ...ev,
  _gcalDescription: description,
  _startRFC: toRFC3339(ev.startTime),
  _endRFC:   ev.endTime ? toRFC3339(ev.endTime) : null,
} }];

// Merge GCal event id from the create response back onto the event item.
const created  = $input.first().json;
const loopItem = $('Loop Over Events').first().json;
const gcalId   = created.id ?? loopItem._gcalEventId ?? null;

if (!gcalId) {
  console.log(`[venue-events-sync] ${loopItem._slug}: could not get GCal event id — skipping DB upsert`);
  return [];
}
return [{ json: { ...loopItem, _gcalEventId: gcalId } }];

// Already exists path — pass the existing GCal event id through.
const ev = $input.first().json;
if (!ev._gcalEventId) {
  console.log(`[venue-events-sync] ${ev._slug}: already in GCal but no id — skipping DB upsert`);
  return [];
}
return [{ json: ev }];

// Build the DB upsert SQL.
// Intentionally does NOT set tag — owned by spm-multi-gcal-to-db-sync tag detection.
// Does NOT overwrite extra_data or image_url if already set for this google_event_id.

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}

const ev = $input.first().json;
if (!ev._gcalEventId) return [];

const extraData = JSON.stringify({
  source:       ev.source       ?? 'facebook',
  fb_event_url: ev.fbEventUrl   ?? null,
  event_by:     ev.eventBy      ?? null,
  dedup_id:     ev.dedup_id     ?? null,
});

const sql = `
INSERT INTO events (
  google_event_id, title, description, start_time, end_time,
  venue, ticket_url, image_url, extra_data, is_active, synced_at
) VALUES (
  ${esc(ev._gcalEventId)},
  ${esc(ev.title)},
  ${esc(ev.description)},
  ${ev.startTime ? esc(ev.startTime) + '::TIMESTAMPTZ' : 'NULL'},
  ${ev.endTime   ? esc(ev.endTime)   + '::TIMESTAMPTZ' : 'NULL'},
  ${esc(ev._slug)},
  ${esc(ev.ticketUrl)},
  ${esc(ev.imageUrl)},
  ${esc(extraData)}::jsonb,
  true,
  NOW()
)
ON CONFLICT (google_event_id) DO UPDATE SET
  title       = EXCLUDED.title,
  description = EXCLUDED.description,
  start_time  = EXCLUDED.start_time,
  end_time    = EXCLUDED.end_time,
  venue       = EXCLUDED.venue,
  ticket_url  = EXCLUDED.ticket_url,
  image_url   = EXCLUDED.image_url,
  extra_data  = EXCLUDED.extra_data,
  is_active   = true,
  synced_at   = NOW()
RETURNING id, google_event_id, title
`.trim();

return [{ json: { sql, title: ev.title, slug: ev._slug } }];

// 300ms throttle between events to stay under GCal API quota.
await new Promise(r => setTimeout(r, 300));
return $input.all();

const cleaned = $input.all();
console.log(`[venue-events-sync] RUN COMPLETE — images cleaned: ${cleaned.length} — ${new Date().toISOString()}`);
return [{ json: { ok: true, images_cleaned: cleaned.length, finished_at: new Date().toISOString() } }];
